body.script:
/**/
// Hamburger menu
function ebToggleMenu(){
  var ham=document.getElementById('eb-ham');
  var menu=document.getElementById('eb-mobile-menu');
  ham.classList.toggle('open');
  menu.classList.toggle('open');
}
// Close mobile menu on link click
document.querySelectorAll('#eb-mobile-menu a').forEach(function(a){
  a.addEventListener('click',function(){
    document.getElementById('eb-ham').classList.remove('open');
    document.getElementById('eb-mobile-menu').classList.remove('open');
  });
});
// Back to top
window.addEventListener('scroll',function(){
  var b=document.getElementById('eb-back-top');
  if(window.scrollY>300)b.classList.add('show');
  else b.classList.remove('show');
});
// Active nav link highlight
(function(){
  var url=window.location.href;
  document.querySelectorAll('#eb-navbar a, #eb-mobile-menu a').forEach(function(a){
    if(a.href&&url.indexOf(a.href)>-1)a.classList.add('active');
  });
})();
// Code block copy buttons
document.querySelectorAll('.eb-post-body pre').forEach(function(pre){
  var btn=document.createElement('button');
  btn.className='eb-copy-btn';
  btn.textContent='Copy';
  btn.onclick=function(){
    var code=pre.querySelector('code');
    if(code){
      navigator.clipboard.writeText(code.innerText).then(function(){
        btn.textContent='Copied!';
        setTimeout(function(){btn.textContent='Copy';},1800);
      });
    }
  };
  pre.style.position='relative';
  pre.appendChild(btn);
});
/**/
